  const sanitized = arg
    .replace(/[^a-zA-Z0-9:_\-]/g, '')  // Allow only safe chars
    .replace(/^([^a-zA-Z_])/, '')       // Must start with letter or _
    .replace(/:$/, '')                  // Remove trailing colon
    .toLowerCase()                      // Normalize case

  // Additional validation for known unsafe values
  const unsafeValues = ['__proto__', 'prototype', 'constructor'];
  if (unsafeValues.includes(sanitized)) {
    return '__unsafe_placeholder';
  }

  return sanitized;
}
```

